def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' not in line:
            continue
        k, v = line.split(':', 1)
        k = k.strip().lower().replace(' ', '_'); v = v.strip()
        if k in ('susceptible', 'infected', 'isolation_capacity'):
            n = int(v) if v.lstrip('-').isdigit() else 0
            out[k] = max(0, n)
    return out
